import{_ as e,o as t,c as o,ag as i}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"插件知识库 (AI)","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/knowledge-base.md","filePath":"zh/guide/knowledge-base.md","lastUpdated":1782688753000}'),s={name:"zh/guide/knowledge-base.md"};function r(l,a,n,d,c,h){return t(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="插件知识库-ai" tabindex="-1">插件知识库 (AI) <a class="header-anchor" href="#插件知识库-ai" aria-label="Permalink to &quot;插件知识库 (AI)&quot;">​</a></h1><p>本页为 AI 助手提供知识库，帮助其更好地理解和使用 EasyYapi 插件。它也是规则页签中 <strong>Help</strong> 按钮打开的页面。</p><h2 id="什么是-easyyapi" tabindex="-1">什么是 EasyYapi？ <a class="header-anchor" href="#什么是-easyyapi" aria-label="Permalink to &quot;什么是 EasyYapi？&quot;">​</a></h2><p>EasyYapi 是一个 IntelliJ IDEA 插件，基于 Javadoc、KDoc 和 ScalaDoc 注释从 Java/Kotlin 源代码生成 API 文档。</p><h2 id="开箱即用" tabindex="-1">开箱即用 <a class="header-anchor" href="#开箱即用" aria-label="Permalink to &quot;开箱即用&quot;">​</a></h2><p>EasyApi 开箱即用地支持标准 HTTP 框架（Spring MVC、WebFlux、JAX-RS、Feign）—— <strong>大多数项目无需自定义规则</strong>。对于扫描器无法察觉的自定义框架行为（例如要求添加请求头的 <code>jakarta.servlet.Filter</code>，或将每个响应包装在信封中的 <code>ResponseBodyAdvice</code>），可使用内置的 AI 助手或外部 skill 来检测并生成规则。完整指南请参见 <a href="/zh/settings/rule-authoring">规则编写</a>。</p><h2 id="关键概念" tabindex="-1">关键概念 <a class="header-anchor" href="#关键概念" aria-label="Permalink to &quot;关键概念&quot;">​</a></h2><ul><li><strong>基于文件夹的规则文件</strong> (3.0+)：项目（<code>&lt;project&gt;/.easyapi/</code>）和全局（<code>~/.easyapi/</code>）作用域下的 <code>.easyapi/*.rules</code> —— 自动发现，变更时自动重载。传统的 <code>.easy.api.config*</code> 文件仍会被读取以保持向后兼容。</li><li><strong>内置 AI 助手</strong>：一个与供应商无关的 AI 服务（基于 LangChain4j）嵌入在规则页签中（Chat / Magic 按钮）。用自然语言编写规则，并且不会在未经明确批准的情况下写入文件。</li><li><strong>外部 <code>easy-yapi-assistant</code> skill</strong>：你可以安装的 skill（<code>npx skills add tangcent/easy-yapi -g -y</code>），以便外部 AI 编码助手（Trae、Cursor、Cline、Continue 等）从与内置助手相同的知识库编写规则。</li><li><strong>配置规则</strong>：自定义文档生成的键值对。参见 <a href="/zh/settings/config-rule">可用配置规则</a>。</li><li><strong>Groovy 脚本</strong>：通过 <code>groovy:</code> 前缀实现的高级自定义。参见 <a href="/zh/settings/tools">脚本工具</a>。</li><li><strong>解析事件</strong>：在解析过程中特定时刻执行的回调。参见 <a href="/zh/settings/">回调与事件</a>。</li><li><strong>脚本工具</strong>：Groovy 脚本中可用的内置工具。</li></ul><h2 id="编写规则的方式" tabindex="-1">编写规则的方式 <a class="header-anchor" href="#编写规则的方式" aria-label="Permalink to &quot;编写规则的方式&quot;">​</a></h2><p>EasyYapi 3.x 提供 <strong>两种方式</strong> 编写规则。两者都写入 <code>.easyapi/*.rules</code> 文件。完整指南请参见 <a href="/zh/settings/rule-authoring">规则编写</a>。</p><table tabindex="0"><thead><tr><th>方式</th><th>适用于</th></tr></thead><tbody><tr><td><a href="/zh/settings/rule-authoring#内置-ai-助手">内置 AI 助手</a></td><td>在 Settings → Rules → Chat / Magic 中用自然语言创建规则</td></tr><tr><td><a href="/zh/settings/rule-authoring#外部-easy-yapi-assistant-skill">外部 <code>easy-yapi-assistant</code> skill</a></td><td>从外部 AI 编码助手驱动规则编写</td></tr></tbody></table><h2 id="常见工作流" tabindex="-1">常见工作流 <a class="header-anchor" href="#常见工作流" aria-label="Permalink to &quot;常见工作流&quot;">​</a></h2><ol><li>从 JetBrains Marketplace 安装插件</li><li>为代码添加 Javadoc/KDoc 注释</li><li>（可选）通过 AI 助手或外部 skill 在 <code>.easyapi/*.rules</code> 文件中编写规则</li><li>将文档导出到 YApi、Postman 或 Markdown</li></ol><h2 id="配置文件位置" tabindex="-1">配置文件位置 <a class="header-anchor" href="#配置文件位置" aria-label="Permalink to &quot;配置文件位置&quot;">​</a></h2><ul><li><strong>项目规则 (3.0+)</strong>: <code>&lt;project&gt;/.easyapi/*.rules</code></li><li><strong>全局规则 (3.0+)</strong>: <code>~/.easyapi/*.rules</code></li><li><strong>传统项目配置</strong>: <code>.easy.api.config</code>（仍会被读取以保持向后兼容）</li><li><strong>远程</strong>：通过 <code>remote.url</code> 配置</li></ul>',15)])])}const u=e(s,[["render",r]]);export{p as __pageData,u as default};
